import{_ as e,o as a,c as s,a2 as n}from"./chunks/framework.CHSDihme.js";const i="/claude-code-token-free/assets/01-agent-overview.DxZaGVuZ.png",o="/claude-code-token-free/assets/02-agent-types.RtionrS2.png",l="/claude-code-token-free/assets/03-spawn-flow.TCnQ-iA8.png",d="/claude-code-token-free/assets/04-agent-teams.wAMqJVPw.png",b=JSON.parse('{"title":"Claude Code Multi-Agent System — Usage Guide","description":"","frontmatter":{},"headers":[],"relativePath":"en/agent/01-usage-guide.md","filePath":"en/agent/01-usage-guide.md","lastUpdated":1780380166000}'),r={name:"en/agent/01-usage-guide.md"};function p(c,t,u,h,g,m){return a(),s("div",null,[...t[0]||(t[0]=[n('<h1 id="claude-code-multi-agent-system--usage-guide" tabindex="-1">Claude Code Multi-Agent System — Usage Guide <a class="header-anchor" href="#claude-code-multi-agent-system--usage-guide" aria-label="Permalink to &quot;Claude Code Multi-Agent System — Usage Guide&quot;">​</a></h1><blockquote><p>Let Claude Code orchestrate multiple specialized agents to handle complex tasks in parallel.</p></blockquote><p align="center"><a href="#1-what-is-the-multi-agent-system">Multi-Agent System</a> · <a href="#2-six-built-in-agents">Six Built-in Agents</a> · <a href="#3-how-to-spawn-agents">Spawning Agents</a> · <a href="#4-background-task-management">Background Tasks</a> · <a href="#5-agent-teams--multi-agent-collaboration">Agent Teams</a> · <a href="#6-custom-agents">Custom Agents</a> · <a href="#7-permission-modes">Permission Modes</a> · <a href="#8-quick-reference">Quick Reference</a></p><p><img src="'+i+'" alt="Multi-Agent System Overview"></p><hr><h2 id="1-what-is-the-multi-agent-system" tabindex="-1">1. What Is the Multi-Agent System? <a class="header-anchor" href="#1-what-is-the-multi-agent-system" aria-label="Permalink to &quot;1. What Is the Multi-Agent System?&quot;">​</a></h2><p>Claude Code&#39;s multi-agent system is an <strong>intelligent task orchestration framework</strong> that enables the primary agent to spawn multiple specialized subagents, each executing different tasks independently, then aggregating results for the user.</p><p>Core philosophy: <strong>Break large tasks into specialized subtasks, execute them in parallel, and boost efficiency.</strong></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Traditional Approach</th><th>Multi-Agent Approach</th></tr></thead><tbody><tr><td>Research 5 module architectures</td><td>Explore them one by one</td><td>5 Explore agents scan in parallel</td></tr><tr><td>Implement + Test + Document</td><td>Complete sequentially</td><td>Team members each handle one part</td></tr><tr><td>Code review</td><td>Single-threaded, file by file</td><td>Multiple reviewers in parallel</td></tr><tr><td>Debug a complex bug</td><td>Try one hypothesis at a time</td><td>Multiple debuggers verify in parallel</td></tr></tbody></table><hr><h2 id="2-six-built-in-agents" tabindex="-1">2. Six Built-in Agents <a class="header-anchor" href="#2-six-built-in-agents" aria-label="Permalink to &quot;2. Six Built-in Agents&quot;">​</a></h2><p><img src="'+o+`" alt="Six Built-in Agents"></p><p>Claude Code ships with 6 specialized agent types, each with a specific tool pool and intended use case:</p><h3 id="21-general-purpose-general-agent" tabindex="-1">2.1 general-purpose (General Agent) <a class="header-anchor" href="#21-general-purpose-general-agent" aria-label="Permalink to &quot;2.1 general-purpose (General Agent)&quot;">​</a></h3><p><strong>Use case</strong>: Complex multi-step research, code search, tasks requiring full tool access.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;Research auth module&quot;,</span></span>
<span class="line"><span>  prompt: &quot;Analyze all files under src/auth/ for the authentication flow...&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;general-purpose&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li><strong>Tool pool</strong>: All tools (<code>*</code>)</li><li><strong>Model</strong>: Inherited from parent</li><li><strong>Characteristics</strong>: The all-rounder — choose this when you are unsure which agent type to use</li></ul><h3 id="22-explore-exploration-agent" tabindex="-1">2.2 Explore (Exploration Agent) <a class="header-anchor" href="#22-explore-exploration-agent" aria-label="Permalink to &quot;2.2 Explore (Exploration Agent)&quot;">​</a></h3><p><strong>Use case</strong>: Quickly search files, find code patterns, answer questions about codebase structure.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;Search API endpoints&quot;,</span></span>
<span class="line"><span>  prompt: &quot;Find all REST API endpoint definitions...&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;Explore&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li><strong>Tool pool</strong>: Read-only tools (Glob, Grep, Read, Bash)</li><li><strong>Model</strong>: Haiku (fast, low cost)</li><li><strong>Characteristics</strong>: Cannot modify files; fast; ideal for research</li></ul><h3 id="23-plan-planning-agent" tabindex="-1">2.3 Plan (Planning Agent) <a class="header-anchor" href="#23-plan-planning-agent" aria-label="Permalink to &quot;2.3 Plan (Planning Agent)&quot;">​</a></h3><p><strong>Use case</strong>: Design implementation plans, analyze architectural trade-offs, generate step-by-step plans.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;Plan refactoring&quot;,</span></span>
<span class="line"><span>  prompt: &quot;Design a plan to split the monolith into microservices...&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;Plan&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li><strong>Tool pool</strong>: Read-only tools (same as Explore)</li><li><strong>Model</strong>: Inherited from parent (requires strong reasoning)</li><li><strong>Characteristics</strong>: Outputs structured plans including key files and dependency analysis</li></ul><h3 id="24-verification-verification-agent" tabindex="-1">2.4 verification (Verification Agent) <a class="header-anchor" href="#24-verification-verification-agent" aria-label="Permalink to &quot;2.4 verification (Verification Agent)&quot;">​</a></h3><p><strong>Use case</strong>: Independently verify that an implementation is correct, run tests, perform boundary checks.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;Verify login feature&quot;,</span></span>
<span class="line"><span>  prompt: &quot;Verify the newly implemented login feature works correctly...&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;verification&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li><strong>Tool pool</strong>: Read-only tools</li><li><strong>Model</strong>: Inherited from parent</li><li><strong>Characteristics</strong>: Always runs in the background; outputs PASS/FAIL/PARTIAL verdicts; displayed with a red badge</li></ul><h3 id="25-claude-code-guide-guide-agent" tabindex="-1">2.5 claude-code-guide (Guide Agent) <a class="header-anchor" href="#25-claude-code-guide-guide-agent" aria-label="Permalink to &quot;2.5 claude-code-guide (Guide Agent)&quot;">​</a></h3><p><strong>Use case</strong>: Answer questions about Claude Code, Agent SDK, or the Claude API.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;Query Claude API usage&quot;,</span></span>
<span class="line"><span>  prompt: &quot;How do I use the tool_use feature...&quot;,</span></span>
<span class="line"><span>  subagent_type: &quot;claude-code-guide&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li><strong>Tool pool</strong>: Bash, Read, WebFetch, WebSearch</li><li><strong>Model</strong>: Haiku</li><li><strong>Characteristics</strong>: Focused on documentation queries; uses the dontAsk permission mode</li></ul><h3 id="26-statusline-setup-status-bar-configuration-agent" tabindex="-1">2.6 statusline-setup (Status Bar Configuration Agent) <a class="header-anchor" href="#26-statusline-setup-status-bar-configuration-agent" aria-label="Permalink to &quot;2.6 statusline-setup (Status Bar Configuration Agent)&quot;">​</a></h3><p><strong>Use case</strong>: Configure the Claude Code status bar display.</p><ul><li><strong>Tool pool</strong>: Read + Edit only</li><li><strong>Model</strong>: Sonnet</li><li><strong>Characteristics</strong>: Highly specialized with an extremely narrow scope</li></ul><h3 id="agent-type-comparison" tabindex="-1">Agent Type Comparison <a class="header-anchor" href="#agent-type-comparison" aria-label="Permalink to &quot;Agent Type Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Access</th><th>Tool Pool</th><th>Model</th><th>Purpose</th></tr></thead><tbody><tr><td>general-purpose</td><td>Read/Write</td><td>All</td><td>Inherited</td><td>General tasks</td></tr><tr><td>Explore</td><td>Read-only</td><td>Search + Read</td><td>Haiku</td><td>Quick exploration</td></tr><tr><td>Plan</td><td>Read-only</td><td>Search + Read</td><td>Inherited</td><td>Architecture planning</td></tr><tr><td>verification</td><td>Read-only</td><td>Search + Read</td><td>Inherited</td><td>Independent verification</td></tr><tr><td>claude-code-guide</td><td>Read-only</td><td>Search + Web</td><td>Haiku</td><td>Documentation guide</td></tr><tr><td>statusline-setup</td><td>Read/Write</td><td>Read + Edit</td><td>Sonnet</td><td>Status bar config</td></tr></tbody></table><hr><h2 id="3-how-to-spawn-agents" tabindex="-1">3. How to Spawn Agents <a class="header-anchor" href="#3-how-to-spawn-agents" aria-label="Permalink to &quot;3. How to Spawn Agents&quot;">​</a></h2><h3 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h3><p>The Agent tool accepts the following parameters:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>description</code></td><td>string</td><td>Yes</td><td>3-5 word task summary</td></tr><tr><td><code>prompt</code></td><td>string</td><td>Yes</td><td>Full task description</td></tr><tr><td><code>subagent_type</code></td><td>string</td><td>No</td><td>Agent type (see table above)</td></tr><tr><td><code>model</code></td><td>string</td><td>No</td><td>Model override: sonnet/opus/haiku</td></tr><tr><td><code>run_in_background</code></td><td>boolean</td><td>No</td><td>Whether to run in background</td></tr><tr><td><code>name</code></td><td>string</td><td>No</td><td>Name the agent so it can be addressed via SendMessage</td></tr><tr><td><code>team_name</code></td><td>string</td><td>No</td><td>Join a specified team</td></tr><tr><td><code>mode</code></td><td>string</td><td>No</td><td>Permission mode</td></tr><tr><td><code>isolation</code></td><td>string</td><td>No</td><td>Isolation mode: worktree</td></tr></tbody></table><h3 id="foreground-synchronous-execution-default" tabindex="-1">Foreground Synchronous Execution (Default) <a class="header-anchor" href="#foreground-synchronous-execution-default" aria-label="Permalink to &quot;Foreground Synchronous Execution (Default)&quot;">​</a></h3><p>The simplest usage — the agent completes and returns its result:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;Analyze error logs&quot;,</span></span>
<span class="line"><span>  prompt: &quot;Read the latest error logs under logs/ and summarize common error patterns&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>The primary agent waits for the subagent to finish, then receives the result and continues working.</p><h3 id="background-asynchronous-execution" tabindex="-1">Background Asynchronous Execution <a class="header-anchor" href="#background-asynchronous-execution" aria-label="Permalink to &quot;Background Asynchronous Execution&quot;">​</a></h3><p>Suitable for time-consuming tasks where the primary agent can continue with other work:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;Full code review&quot;,</span></span>
<span class="line"><span>  prompt: &quot;Review all TypeScript files under src/ for code quality...&quot;,</span></span>
<span class="line"><span>  run_in_background: true</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li>The agent immediately returns an <code>async_launched</code> status with a taskId</li><li>The primary agent continues working without waiting</li><li>When the agent completes, a <code>&lt;task-notification&gt;</code> is delivered automatically</li><li>The notification includes task status, output file path, and a result summary</li></ul><h3 id="spawning-multiple-agents-in-parallel" tabindex="-1">Spawning Multiple Agents in Parallel <a class="header-anchor" href="#spawning-multiple-agents-in-parallel" aria-label="Permalink to &quot;Spawning Multiple Agents in Parallel&quot;">​</a></h3><p>Spawn multiple independent agents in a single message for true parallelism:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Launch 3 explore agents simultaneously</span></span>
<span class="line"><span>Agent({ description: &quot;Explore frontend&quot;, prompt: &quot;...&quot;, subagent_type: &quot;Explore&quot;, run_in_background: true })</span></span>
<span class="line"><span>Agent({ description: &quot;Explore backend&quot;, prompt: &quot;...&quot;, subagent_type: &quot;Explore&quot;, run_in_background: true })</span></span>
<span class="line"><span>Agent({ description: &quot;Explore database&quot;, prompt: &quot;...&quot;, subagent_type: &quot;Explore&quot;, run_in_background: true })</span></span></code></pre></div><h3 id="worktree-isolation" tabindex="-1">Worktree Isolation <a class="header-anchor" href="#worktree-isolation" aria-label="Permalink to &quot;Worktree Isolation&quot;">​</a></h3><p>Let an agent work in an isolated git worktree without affecting the main workspace:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;Experimental refactor&quot;,</span></span>
<span class="line"><span>  prompt: &quot;Try refactoring module X into...&quot;,</span></span>
<span class="line"><span>  isolation: &quot;worktree&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li>Automatically creates a git worktree (on an independent branch)</li><li>The agent can freely modify files in the isolated environment</li><li>If changes were made, returns the worktree path and branch name on completion</li><li>If no changes were made, cleans up automatically</li></ul><hr><h2 id="4-background-task-management" tabindex="-1">4. Background Task Management <a class="header-anchor" href="#4-background-task-management" aria-label="Permalink to &quot;4. Background Task Management&quot;">​</a></h2><p><img src="`+l+`" alt="Agent Spawn Flow"></p><h3 id="task-states" tabindex="-1">Task States <a class="header-anchor" href="#task-states" aria-label="Permalink to &quot;Task States&quot;">​</a></h3><p>Background agents have four possible states:</p><table tabindex="0"><thead><tr><th>State</th><th>Description</th></tr></thead><tbody><tr><td><code>running</code></td><td>Currently executing</td></tr><tr><td><code>completed</code></td><td>Finished successfully</td></tr><tr><td><code>failed</code></td><td>Execution failed</td></tr><tr><td><code>killed</code></td><td>Manually terminated</td></tr></tbody></table><h3 id="progress-tracking" tabindex="-1">Progress Tracking <a class="header-anchor" href="#progress-tracking" aria-label="Permalink to &quot;Progress Tracking&quot;">​</a></h3><p>Background agent progress updates in real time:</p><ul><li><strong>Token usage</strong>: Input/output token counts</li><li><strong>Tool usage</strong>: Number of tools invoked</li><li><strong>Recent activity</strong>: Descriptions of the last 5 tool calls (circular buffer)</li><li><strong>Last activity time</strong>: Used to detect stuck tasks</li></ul><h3 id="completion-notifications" tabindex="-1">Completion Notifications <a class="header-anchor" href="#completion-notifications" aria-label="Permalink to &quot;Completion Notifications&quot;">​</a></h3><p>When a background agent finishes, the primary agent receives an XML-formatted notification:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">task-notification</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">task-id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;abc123&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">task-id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">status</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;completed&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">status</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">summary</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Agent &quot;Explore frontend&quot; completed&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">summary</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">output-file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;~/.claude/temp/.../tasks/abc123.output&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">output-file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">task-notification</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h3 id="automatic-backgrounding" tabindex="-1">Automatic Backgrounding <a class="header-anchor" href="#automatic-backgrounding" aria-label="Permalink to &quot;Automatic Backgrounding&quot;">​</a></h3><p>When the <code>tengu_auto_background_agents</code> feature flag is enabled, foreground agents that run for more than <strong>120 seconds</strong> are automatically moved to background execution, freeing the primary agent to continue working.</p><hr><h2 id="5-agent-teams--multi-agent-collaboration" tabindex="-1">5. Agent Teams — Multi-Agent Collaboration <a class="header-anchor" href="#5-agent-teams--multi-agent-collaboration" aria-label="Permalink to &quot;5. Agent Teams — Multi-Agent Collaboration&quot;">​</a></h2><p><img src="`+d+`" alt="Agent Teams Collaboration"></p><p>Agent Teams is an advanced multi-agent collaboration mode where multiple agents work as a team, coordinating tasks through message-based communication.</p><h3 id="creating-a-team" tabindex="-1">Creating a Team <a class="header-anchor" href="#creating-a-team" aria-label="Permalink to &quot;Creating a Team&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TeamCreate({</span></span>
<span class="line"><span>  team_name: &quot;feature-team&quot;,</span></span>
<span class="line"><span>  description: &quot;Develop user authentication feature&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>After team creation:</p><ul><li>A team configuration file is generated: <code>~/.claude/teams/{team_name}/config.json</code></li><li>A shared task directory is created: <code>~/.claude/tasks/{team_name}/</code></li><li>The current agent automatically becomes the <strong>Team Lead</strong></li></ul><h3 id="adding-team-members" tabindex="-1">Adding Team Members <a class="header-anchor" href="#adding-team-members" aria-label="Permalink to &quot;Adding Team Members&quot;">​</a></h3><p>Spawn teammates by specifying <code>name</code> and <code>team_name</code> in the Agent tool:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;Frontend development&quot;,</span></span>
<span class="line"><span>  prompt: &quot;Implement the login page React components...&quot;,</span></span>
<span class="line"><span>  name: &quot;frontend-dev&quot;,</span></span>
<span class="line"><span>  team_name: &quot;feature-team&quot;</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Agent({</span></span>
<span class="line"><span>  description: &quot;Backend development&quot;,</span></span>
<span class="line"><span>  prompt: &quot;Implement the authentication API endpoints...&quot;,</span></span>
<span class="line"><span>  name: &quot;backend-dev&quot;,</span></span>
<span class="line"><span>  team_name: &quot;feature-team&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><h3 id="teammate-communication" tabindex="-1">Teammate Communication <a class="header-anchor" href="#teammate-communication" aria-label="Permalink to &quot;Teammate Communication&quot;">​</a></h3><p>Send messages using the SendMessage tool:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Send to a specific teammate</span></span>
<span class="line"><span>SendMessage({</span></span>
<span class="line"><span>  to: &quot;frontend-dev&quot;,</span></span>
<span class="line"><span>  message: &quot;API interface is ready, the format is...&quot;,</span></span>
<span class="line"><span>  summary: &quot;Notify API interface format&quot;</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Broadcast to all teammates</span></span>
<span class="line"><span>SendMessage({</span></span>
<span class="line"><span>  to: &quot;*&quot;,</span></span>
<span class="line"><span>  message: &quot;Everyone pause, requirements have changed...&quot;,</span></span>
<span class="line"><span>  summary: &quot;Broadcast requirements change&quot;</span></span>
<span class="line"><span>})</span></span></code></pre></div><h3 id="shutdown-coordination" tabindex="-1">Shutdown Coordination <a class="header-anchor" href="#shutdown-coordination" aria-label="Permalink to &quot;Shutdown Coordination&quot;">​</a></h3><p>When the task is complete, the Team Lead requests teammates to shut down:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 1. Send shutdown request</span></span>
<span class="line"><span>SendMessage({</span></span>
<span class="line"><span>  to: &quot;frontend-dev&quot;,</span></span>
<span class="line"><span>  message: { type: &quot;shutdown_request&quot;, reason: &quot;Task completed&quot; }</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 2. Teammate responds with approval</span></span>
<span class="line"><span>SendMessage({</span></span>
<span class="line"><span>  to: &quot;team-lead&quot;,</span></span>
<span class="line"><span>  message: { type: &quot;shutdown_response&quot;, request_id: &quot;...&quot;, approve: true }</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 3. After all teammates shut down, clean up the team</span></span>
<span class="line"><span>TeamDelete()</span></span></code></pre></div><h3 id="execution-backends" tabindex="-1">Execution Backends <a class="header-anchor" href="#execution-backends" aria-label="Permalink to &quot;Execution Backends&quot;">​</a></h3><p>Agent Teams supports two execution backends:</p><table tabindex="0"><thead><tr><th>Backend</th><th>Description</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>in-process</strong></td><td>Runs in the same process, isolated via AsyncLocalStorage</td><td>Default mode; lightweight and efficient</td></tr><tr><td><strong>tmux</strong></td><td>Runs in a separate tmux pane</td><td>When an independent terminal view is needed</td></tr><tr><td><strong>iTerm2</strong></td><td>Runs in a separate iTerm2 window</td><td>For macOS iTerm2 users</td></tr></tbody></table><hr><h2 id="6-custom-agents" tabindex="-1">6. Custom Agents <a class="header-anchor" href="#6-custom-agents" aria-label="Permalink to &quot;6. Custom Agents&quot;">​</a></h2><p>In addition to built-in agents, you can create your own specialized agents.</p><h3 id="definition-format" tabindex="-1">Definition Format <a class="header-anchor" href="#definition-format" aria-label="Permalink to &quot;Definition Format&quot;">​</a></h3><p>Create a <code>.md</code> file in the <code>.claude/agents/</code> directory:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name: code-reviewer</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">description: Professional code review agent</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tools:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Read</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Grep</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Glob</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Bash</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">model: sonnet</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">permissionMode: dontAsk</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">maxTurns: 10</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">You are a professional code reviewer. Check the following aspects:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Code quality and readability</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Potential security vulnerabilities</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Performance issues</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Adherence to best practices</span></span></code></pre></div><h3 id="configurable-fields" tabindex="-1">Configurable Fields <a class="header-anchor" href="#configurable-fields" aria-label="Permalink to &quot;Configurable Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>name</code></td><td>string</td><td>Agent type name</td></tr><tr><td><code>description</code></td><td>string</td><td>Description of when to use this agent</td></tr><tr><td><code>tools</code></td><td>string[]</td><td>Allowed tool list (<code>[&#39;*&#39;]</code> for all)</td></tr><tr><td><code>disallowedTools</code></td><td>string[]</td><td>Disallowed tool list</td></tr><tr><td><code>model</code></td><td>string</td><td>Model to use (sonnet/opus/haiku/inherit)</td></tr><tr><td><code>permissionMode</code></td><td>string</td><td>Permission mode</td></tr><tr><td><code>maxTurns</code></td><td>number</td><td>Maximum conversation turns</td></tr><tr><td><code>mcpServers</code></td><td>object[]</td><td>Required MCP servers</td></tr><tr><td><code>hooks</code></td><td>object</td><td>Agent-specific hooks</td></tr><tr><td><code>skills</code></td><td>string[]</td><td>Available skills</td></tr><tr><td><code>memory</code></td><td>string</td><td>Memory scope (user/project/local)</td></tr><tr><td><code>isolation</code></td><td>string</td><td>Isolation mode (worktree/remote)</td></tr><tr><td><code>background</code></td><td>boolean</td><td>Whether to run in background by default</td></tr></tbody></table><h3 id="loading-priority" tabindex="-1">Loading Priority <a class="header-anchor" href="#loading-priority" aria-label="Permalink to &quot;Loading Priority&quot;">​</a></h3><p>Custom agents are loaded according to the following priority:</p><ol><li><strong>Built-in agents</strong> (built-in) — System predefined</li><li><strong>Plugin agents</strong> (plugin) — Registered via plugins</li><li><strong>User agents</strong> (user) — <code>~/.claude/agents/</code></li><li><strong>Project agents</strong> (project) — <code>.claude/agents/</code> (project-level)</li><li><strong>Flag agents</strong> (flag) — Registered via API</li><li><strong>Policy agents</strong> (policy) — Organization policies</li></ol><p>Agents with the same name are overridden according to priority.</p><hr><h2 id="7-permission-modes" tabindex="-1">7. Permission Modes <a class="header-anchor" href="#7-permission-modes" aria-label="Permalink to &quot;7. Permission Modes&quot;">​</a></h2><p>Each agent can be configured with a different permission mode:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td><code>default</code></td><td>Normal permission requests requiring user confirmation</td></tr><tr><td><code>plan</code></td><td>All operations require explicit approval</td></tr><tr><td><code>acceptEdits</code></td><td>File edits are auto-approved; other operations require confirmation</td></tr><tr><td><code>bypassPermissions</code></td><td>Skip all permission checks</td></tr><tr><td><code>dontAsk</code></td><td>Reject all operations not pre-approved</td></tr><tr><td><code>auto</code></td><td>AI-driven permission classification (Anthropic internal only)</td></tr><tr><td><code>bubble</code></td><td>Permission prompts bubble up to the parent agent&#39;s terminal</td></tr></tbody></table><hr><h2 id="8-quick-reference" tabindex="-1">8. Quick Reference <a class="header-anchor" href="#8-quick-reference" aria-label="Permalink to &quot;8. Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Method</th></tr></thead><tbody><tr><td>Spawn a subagent</td><td><code>Agent({ prompt: &quot;...&quot;, subagent_type: &quot;Explore&quot; })</code></td></tr><tr><td>Run in background</td><td><code>Agent({ ..., run_in_background: true })</code></td></tr><tr><td>Spawn in parallel</td><td>Send multiple Agent calls in a single message</td></tr><tr><td>Worktree isolation</td><td><code>Agent({ ..., isolation: &quot;worktree&quot; })</code></td></tr><tr><td>Create a team</td><td><code>TeamCreate({ team_name: &quot;...&quot; })</code></td></tr><tr><td>Send a message</td><td><code>SendMessage({ to: &quot;name&quot;, message: &quot;...&quot; })</code></td></tr><tr><td>Broadcast a message</td><td><code>SendMessage({ to: &quot;*&quot;, message: &quot;...&quot; })</code></td></tr><tr><td>Request shutdown</td><td><code>SendMessage({ to: &quot;name&quot;, message: { type: &quot;shutdown_request&quot; } })</code></td></tr><tr><td>Delete a team</td><td><code>TeamDelete()</code></td></tr><tr><td>Custom agent</td><td>Create a definition file in <code>.claude/agents/*.md</code></td></tr><tr><td>Specify a model</td><td><code>Agent({ ..., model: &quot;haiku&quot; })</code></td></tr><tr><td>Name an agent</td><td><code>Agent({ ..., name: &quot;researcher&quot; })</code></td></tr></tbody></table>`,111)])])}const y=e(r,[["render",p]]);export{b as __pageData,y as default};
